INSERT INTO `domain_lifestyle` (`id`, `user_id`, `entry_date`, `user_data`, `ai_text`, `created_at`) VALUES
(1, 5, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 9.0, \"today_stress_level\": 1, \"average_sleep_hours\": 9.0, \"average_stress_level\": 1.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 9.0, \"stress_level\": 1}]}', 'Great job on your sleep and managing stress! To keep that excellent momentum, try to maintain a consistent sleep schedule, even on weekends.', '2026-03-09 12:52:14'),
(2, 5, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 15.0, \"today_stress_level\": 1, \"average_sleep_hours\": 15.0, \"average_stress_level\": 1.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 15.0, \"stress_level\": 1}]}', 'Try to wake up at a consistent time each day to help regulate your sleep rhythm.', '2026-03-09 12:52:53'),
(3, 5, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 12.0, \"today_stress_level\": 1, \"average_sleep_hours\": 12.0, \"average_stress_level\": 1.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 12.0, \"stress_level\": 1}]}', 'Aim for a consistent wake-up time each day to help regulate your body\'s natural sleep rhythm.', '2026-03-09 12:53:37'),
(4, 5, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 20.0, \"today_stress_level\": 1, \"average_sleep_hours\": 20.0, \"average_stress_level\": 1.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 20.0, \"stress_level\": 1}]}', 'Establishing a regular wake-up time, even on weekends, can help your body find a healthier sleep rhythm.', '2026-03-09 12:54:39'),
(5, 5, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 20.0, \"today_stress_level\": 1, \"average_sleep_hours\": 20.0, \"average_stress_level\": 1.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 20.0, \"stress_level\": 1}]}', 'Try to wake up around the same time each day to help regulate your sleep cycle.', '2026-03-09 13:04:19'),
(6, 4, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 10.0, \"today_stress_level\": 2, \"average_sleep_hours\": 10.0, \"average_stress_level\": 2.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 10.0, \"stress_level\": 2}]}', 'Aim for a consistent sleep schedule by going to bed and waking up around the same time each day, even on weekends.', '2026-03-09 13:13:10'),
(7, 4, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 8.0, \"today_stress_level\": 6, \"average_sleep_hours\": 8.0, \"average_stress_level\": 6.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 8.0, \"stress_level\": 6}]}', 'To gently ease your stress, try taking a few deep, slow breaths whenever you feel overwhelmed today.', '2026-03-09 13:13:40'),
(8, 4, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 7.0, \"today_stress_level\": 6, \"average_sleep_hours\": 7.0, \"average_stress_level\": 6.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 7.0, \"stress_level\": 6}]}', 'When you feel stress building, try taking a few slow, deep breaths. It\'s a simple way to help calm your mind.', '2026-03-09 13:14:32'),
(9, 4, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 9.0, \"today_stress_level\": 3, \"average_sleep_hours\": 9.0, \"average_stress_level\": 3.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 9.0, \"stress_level\": 3}]}', 'Try to keep your bedtime and wake-up time consistent, even on weekends, for optimal sleep rhythm.', '2026-03-09 13:18:50'),
(10, 4, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 5.0, \"today_stress_level\": 9, \"average_sleep_hours\": 5.0, \"average_stress_level\": 9.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 5.0, \"stress_level\": 9}]}', 'Given your high stress, try taking a few slow, deep breaths to gently calm your mind.', '2026-03-09 13:19:03'),
(11, 4, '2026-03-09', '{\"today_date\": \"2026-03-09\", \"today_sleep_hours\": 6.0, \"today_stress_level\": 1, \"average_sleep_hours\": 6.0, \"average_stress_level\": 1.0, \"entries\": [{\"date\": \"2026-03-09\", \"sleep_hours\": 6.0, \"stress_level\": 1}]}', 'To gently encourage a bit more rest, try winding down just 15 minutes earlier tonight.', '2026-03-09 13:19:20'),
