(130, 5, '2026-03-25', '{\"tasks\": [], \"completed_today\": 0, \"total_tasks_today\": 0, \"upcoming_titles\": []}', 'What\'s one small step you can take right now to get closer to a goal? Do just that.', '2026-03-25 13:43:14'),
(131, 5, '2026-03-25', '{\"tasks\": [], \"completed_today\": 0, \"total_tasks_today\": 0, \"upcoming_titles\": []}', 'Pick just one tiny task you can finish in 5 minutes to get started.', '2026-03-25 13:43:15'),
(132, 5, '2026-03-25', '{\"tasks\": [{\"id\": \"1774426394671\", \"title\": \"food\", \"time_millis\": 1774428190942, \"completed\": true}, {\"id\": \"1774426400705\", \"title\": \"attendance\", \"time_millis\": 1774428197383, \"completed\": false}], \"completed_today\": 1, \"total_tasks_today\": 2, \"upcoming_titles\": [\"attendance\"]}', 'Pick one task to focus on, then commit to it fully until your next planned break.', '2026-03-25 13:43:22'),
(133, 5, '2026-03-25', '{\"tasks\": [{\"id\": \"1774426394671\", \"title\": \"food\", \"time_millis\": 1774428190942, \"completed\": true}, {\"id\": \"1774426400705\", \"title\": \"attendance\", \"time_millis\": 1774428197383, \"completed\": true}], \"completed_today\": 2, \"total_tasks_today\": 2, \"upcoming_titles\": []}', 'Eat mindfully to truly recharge your focus.', '2026-03-25 13:43:25'),
(134, 5, '2026-03-25', '{\"tasks\": [{\"id\": \"1774426394671\", \"title\": \"food\", \"time_millis\": 1774428190942, \"completed\": true}, {\"id\": \"1774426400705\", \"title\": \"attendance\", \"time_millis\": 1774428197383, \"completed\": true}], \"completed_today\": 2, \"total_tasks_today\": 2, \"upcoming_titles\": []}', 'Identify your Most Important Task (MIT) first thing each morning.', '2026-03-25 13:43:26'),
(135, 5, '2026-03-25', '{\"tasks\": [{\"id\": \"1774426394671\", \"title\": \"food\", \"time_millis\": 1774428190942, \"completed\": true}, {\"id\": \"1774426400705\", \"title\": \"attendance\", \"time_millis\": 1774428197383, \"completed\": true}], \"completed_today\": 2, \"total_tasks_today\": 2, \"upcoming_titles\": []}', 'Dedicate a short, focused burst to your final task before shifting your UniMind to attendance.', '2026-03-25 13:43:28'),
(136, 5, '2026-03-25', '{\"tasks\": [{\"id\": \"1774426394671\", \"title\": \"food\", \"time_millis\": 1774428190942, \"completed\": true}, {\"id\": \"1774426400705\", \"title\": \"attendance\", \"time_millis\": 1774428197383, \"completed\": true}], \"completed_today\": 2, \"total_tasks_today\": 2, \"upcoming_titles\": []}', 'Before your attendance, take 2 minutes to mentally review what it\'s about. What\'s one key thing you want to get from it?', '2026-03-25 13:43:30'),
(137, 5, '2026-03-25', '{\"tasks\": [{\"id\": \"1774426394671\", \"title\": \"food\", \"time_millis\": 1774428190942, \"completed\": true}, {\"id\": \"1774426400705\", \"title\": \"attendance\", \"time_millis\": 1774428197383, \"completed\": true}], \"completed_today\": 2, \"total_tasks_today\": 2, \"upcoming_titles\": []}', 'Great job clearing your tasks! Now, take 5 minutes to decide on the single most impactful task for when new work arrives.', '2026-03-25 13:43:35');
